(window.webpackJsonp=window.webpackJsonp||[]).push([[39],{421:function(n,v,_){"use strict";_.r(v);var p=_(1),l=Object(p.a)({},(function(){var n=this,v=n._self._c;return v("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[v("p",[n._v("01五维话术（说话的底气来自实力）")]),n._v(" "),v("p",[n._v("之所以有人抱怨“干得好不如说得好”，之所以企业越来越强调当众表达力，之所以创业者越来越注重个人魅力和演讲的功夫，不是因为做事不重要，而是因为在大家能干的活越来越趋同的时候，说话变得更加重要。")]),n._v(" "),v("p",[n._v("我们日常生活里大部分的“说错话”，不过是因为没搞清权力的归属，错误地理解了场景，从一开始就选错了策略。")]),n._v(" "),v("p",[n._v("演讲：权力的形成；经典的演讲视频，会发现演讲者最开始都会有一个成功的破冰，也就是在三言两语间拉近与听众的距离——先获得观众的心理认可，再来传达真正重要的信息。\n沟通：因为沟通是“权力的流动”，重在拉平二者的关系，让双方都能讲出自己的真实想法，所以我们需要的不但不是刨根问底，反而是要像激流中的划艇者那样，在容易触礁的地方不断协调转向，避免冲撞。\n说服：说服的关键，就是要尊重并且利用对方的自主性，使其从自身角度出发，心悦诚服地接受我们所希望其接受的观点。我们要卸下对方的心理防御机制，诉诸对方自身的心理需求，让“我说服了你”变成“你说服了自己”，让“我的观念打败了你的观念”变成“你的观念升级了”。这既不是卑躬屈膝，也不是蛊惑人心，而是对说话中真实存在着的权力关系表示尊重。\n谈判：其实，当方案各有优劣、谁也说服不了谁的时候，我们所面临的场景是谈判，而不是沟通，而这是一种“权力在双方”的情况。此时我们需要的是把各自的目的、诉求、损益摆到台面上来谈，通过讨价还价的利益交换，尽快确定一个双方都可以接受的版本。\n辩论：对手其实并不重要，他们只是我们向第三方证明自己正确的一个工具。这是辩论的基本策略，也是辩论讲究风度的根本原因。")]),n._v(" "),v("p",[n._v("在任何一个场域里，我们都必须通过聆听和观察收集足够的信息，来判断权力归属和场景。")]),n._v(" "),v("p",[n._v("演讲时要建立一个轻松的气氛，放松自己紧绷的情绪，就要先和自己的支持者建立语言和情绪上的默联结。很多有经验的演讲者在开始正式讲话前，会先与台前比较靠近的人握手。（权力的形成）\n \n沟通：沟通偏重“理解”，目的是要学会怎样体会别人的角色、照顾别人的诉求。\n说服：服的要义，是时刻警醒“权力在对方”，作为无权的一方，我们需要用各种迂回的手段达成目的。\n谈判：谈判的目的不是单纯为了比拼彼此的筹码，而是希望能够透过博弈建立双方的信任，汇集双方的思考，进一步创造彼此的筹码，避免零和博弈。\n演讲：演讲偏重“表现”，目的是能够自在、得体、有逻辑地向一般听众进行陈述。这是一个人建立自我身份、传递个人特色的最基本素养。\n辩论：好的辩论并非源于好斗的低劣本能，而是基于高等教育所倡导的批判性思维方法。")]),n._v(" "),v("p",[n._v("第二章 沟通\n建立基本共识、扩充对话时间、调整预设认知以及释放可能的善意。\n买时间策略：时间既是阻碍沟通最大的绊脚石，也是成就沟通最好的催化剂。\n先别忙着去埋头想自己要讲什么，而要先去思考——如何才能让别人愿意花更多的时间听？\n我们得先给自己争取到时间，才有机会说清楚自己的想法。\n当表达的时间受限时，千万不要继续一根筋地按照原本的思路讲下去，也不要把话说得跟连珠炮似的，而要首先考虑为自己买时间，让对方有耐心听，我们才有可能完整地表达自己的思路。\n这招买时间，只能用于对方不给你时间，而非情势不给你时间的情况。所以当你衡量现实状况，发现紧迫的不是人，而是局势时（譬如失火了），还是要长话短说。\n其次，够胆买时间，你就得有底气用好买来的时间，不然你成功地引起了关注，最后没讲出什么东西来，只会失败得更惨。")]),n._v(" "),v("p",[n._v("●关于这件事，如果您不给我时间解释，那就是逼着我说谎话了。")]),n._v(" "),v("p",[n._v("报告坏消息的时候，最常见的误区就是因为要表现出感同身受，反而让自己受牵连，成为被指责的对象。\n报告坏消息时的第二个误区，就是我们经常会混淆“善意”和“愧疚”这两种情绪。为了表达自己没有恶意，很多人开口就是“对不起”，换来的却未必是对方的心平气和，反而很可能是一句恶狠狠的话：“说对不起有用吗？你得给我解决！”\n第三个误区，则是有些富于行动力的人，在传递坏消息的同时，为了安抚接收方，也为了避免自责，往往会主动出言安慰，甚至出谋划策，试图帮对方解决整个问题，却忽略了这样做其实很容易有失分寸，并伴随着极大的风险。当你主动安慰的时候，就将自己的身份由“不承担责任的传达者”转变成了“要承担责任的行动方”。\n日常生活中，我们常教导大家要有人情味一点，但是在传递坏消息的时候，我们更需要展示出的应该是一种中立的姿态，既不过分亲热，又不过分冷漠，才能做到既准确忠实地传递消息，又不会进一步刺激到接收方的情绪。\n说话要清楚有力，不要支支吾吾；眼神要直视，不要躲躲闪闪。\n所以要记住，不论我们有多善解人意，我们都只是来传达消息的，而不是来道歉的，说句“很遗憾”也就行了，不要上升到愧疚、抱歉这种话。注意这一点情绪上的微妙差别，很多时候就可以避免后续的无尽麻烦。\n报告坏消息的时候，最好是在一个封闭或者半封闭的空间，而且最好是先跟对方一起坐下来。\n可以陪伴，但千万不要主动安慰。无论是想当然地说一些自以为“体贴”的话，还是用主动的肢体语言，比如握住对方的手或拍拍背来安慰人，抑或是给出所谓“积极的”解决方案，都不可取。要时刻牢记，作为“报丧者”这样一个天然就不讨好的角色，分寸重于一切，任何越界的行为都有可能节外生枝，给双方都带来不必要的麻烦。\n请注意，这里谈到的“传递坏消息”的分寸和技巧有一个适用范围，那就是这件坏事并非由你造成，你只不过是因为身份、职业使然的一个传递渠道而已。\n要专业而不要同情，要善意而不要愧疚，要陪伴而不要主动安慰。")]),n._v(" "),v("ol",[v("li",[n._v("我来说明一下，这件事情是这样的……")]),n._v(" "),v("li",[n._v("我很遗憾，情况并不乐观……")]),n._v(" "),v("li",[n._v("有任何疑问你都可以问我，我会告诉你我所知道的一切信息。")])]),n._v(" "),v("p",[n._v("迅速真诚地营造关系\n破解初次见面的尴尬\n误区：没话题？聊隐私\n应对方法：聊名字\n第一，陌生人相遇，一开口永远是请教姓名。所以既然开了这个头，不如接下去，也省得额外找话题。\n第二，即便再怎么不了解对方的背景或嗜好，但有一点是永远不变的，那就是每个人总是对他（她）自己最有兴趣。所以跟别人问起名字的寓意、取名的由来，或者聊几句称呼或绰号的趣闻，既能表现出你对陌生朋友的重视，又绝不怕冒犯对方。\n在短短两三个字中常常融入大量的寓意、典故与期盼。甚至有时候，名字还包括了家族的族谱用字、长幼排序、五行风水。如果我们恰好懂得对方名字里的典故，几乎一上来就可以给对方留下不错的印象。\n使用注意：重点主要是针对那些萍水相逢、没有打算深交的陌生人之间，用来填补尴尬的社交空白时使用。如果面对的是想要更进一步拉近关系的对象，譬如重要的客户或心仪的女神，那么光聊名字反而会因为过于客套而造成距离感，使用时要谨慎。")]),n._v(" "),v("p",[n._v("用聊八卦拉近距离\n误区：聊天，完全不能涉及私生活\n从大家身边的事情出发，谈及私生活，也就是俗称的八卦，虽然听起来容易冒犯人，但却是真正跟人打开心扉、拉近距离的必选方式。\n应对方法：\n不给对方施加压力")]),n._v(" "),v("ol",[v("li",[n._v("不要索取信息，而要分享态度\n这类问题就比较不会伤人，因为“喜不喜欢”或“容不容易”只是表达态度，聊起来没有压力。且态度这东西，聊着聊着，对方往往就会很自然地变成跟我们分享信息。\n同样，当以后想问别人“有没有买房”或“有没有女朋友”之类的问题时，你也不妨调整一下，改成：“你觉得现在这个时候投资房子可行吗？”或者：“我觉得女生真是麻烦，有时候还不如一个人呢！”\n像这样，把态度问题抛出去，对方自然就会聊到我们想要知道的信息。")]),n._v(" "),v("li",[n._v("抛砖引玉，以自我揭短的方式向对方抛出话题\n在这里你先对自我状态进行否定式陈述，让对方感受不到压力。之后再问问题。")]),n._v(" "),v("li",[n._v("把问题抛给在场的所有人，而不是特意面向某个人\n多人聊天时，众口难调。而只要我们提出的问题能够引起共鸣，总会有人接话茬，大家聊开了，自然就会你一言、我一语，更多的信息就出来了。聊八卦时应以不给对方压力为大原则，做到不索要信息、不炫耀自己、不具体针对，才能既拉近关系，又避免冒犯。\n第二点注意事项“自我揭短”，不是要你说谎话，总不能男朋友明明送了你包包，却故意装可怜说没送，好去套对方的隐私。这种行为，日后一旦被抓到，会留下极坏的风评。")])]),n._v(" "),v("p",[n._v("委婉礼貌地拒绝对方\n误区：借钱？借多少？\n其次，除非你问完之后毫不迟疑地拿出钱包，否则你同时也失去了借钱给对方时原本可以收获的人情。\n方法：")]),n._v(" "),v("ol",[v("li",[n._v("别关心金额，先关心原因\n此时，对方说出的借钱理由也不外乎两种：\n1.救急 如果对方借钱的数额实在太大，借不了那么多，或是压根儿不想陷入无止境的催钱与拖债中，也可以将你认为合适的金额用包个红包的方式送给对方，而原本是想借钱的亲友也不太可能挑你的理。\n2.免息 当对方说出诸如买房之类的借钱理由时，不要马上说“买房啊，不借”这样让人尴尬的话，而是要进一步以关切的态度来确定对方缺钱的原因，比如：“买房首付不够啊，理解理解，现在房子的确太贵了。” 而探听清楚原因后，接下来，我们就可以根据对方的原因给出一个不借的相似理由，用来拒绝对方。直接表明与对方遭遇一样的困境，还可以借势与对方一起抱怨老板，情感上也可以下得了台阶。\n这个诀窍的巧妙之处在于：当对方以某种原因为理由向你借钱时，对方一定会觉得这个理由本身很有说服力，他人无法拒绝，而用同样的理由来拒绝对方时，他也同样没办法再接着纠缠，或否定你的理由不重要。\n句式：\n●你最近是遇到什么困难了吗？\n●我也遇到了一样的问题，真抱歉没法帮到你")])]),n._v(" "),v("p",[n._v("冲突时不要寻求结论与解答\n在冲突沟通中，我们在意的并不是寻求一个具体的结论或问题的解答，而是借由冲突的发生宣泄压抑的情绪、表达自我的感受，以及促进双方的理解。\n小诀窍：\n当你想要宣泄情绪、表达不满之前，试着做一些这样的铺垫：“抱歉，这或许未必是事实，但我难免会有这种感觉。”")]),n._v(" "),v("p",[n._v("怎么说话不得罪人\n如果改成描述自己的感受，我们就巧妙地把评价别人转换成陈述自己的状态。\n其次，要怎么避免给人留下漠不关心的印象呢？那就是在安慰的时候，最好强调人，用“这件事对你真可惜，但你的付出，我都知道”来取代“别难过，这件事根本不重要”。\n比如，你与其表示：“没事的，我是过来人，这都是小事！”还不如说：“唉，我知道你花了很多时间和心血，结果变成这样，真是非常可惜。\n求人办事就要一股脑地把想办什么事、有什么地方需要帮忙、事情的来龙去脉是什么、哪些方面是有顾虑的、有没有什么实际的好处等事先想明白、跟人说清楚，才算是尽到了求人帮忙的义务。\n常用例句：你这样做让我…… 我认为你做得真的很好，只不过这件事情…… 你好，我有件事情想找你帮忙，事情是这样的……打扰了！\n \n如何面对自己的情绪：这个时候，你倒不如直说自己有情绪，说得越坦诚、需求越具体，对方就越会照顾我们的情绪。\n妥善应对别人的情绪：隔离、同理与拦截\n在与别人沟通之前，先要保证自己的状态。所谓给自己做心理隔离，就是自己跟自己进行理性对话，以达到心理隔离的状态。\n在客户喋喋不休的时候，你可以尝试着把全部注意力都用来寻找客户话语中的高频词汇，很快你就会发现这位发脾气的客户之所以情绪上涌的真实原因。\n同理心句型，就是通过重述对方的现状，来让对方知道我们可以看到并理解他的情绪，从而达到疏导情绪的目的。面对一个愤怒的人，正确的姿态永远不是站在对立面，而应站在同一边。\n愤怒的人会口不择言，一般情况下我们用心理隔离的方式避免卷入即可，但是有些话，我们不能选择听而不闻。比如涉及性别歧视、地域歧视、人格侮辱的话，哪怕是老板讲的，也是很不应该的。但是，回击会让战事升级，不回击又是对自己和别人的不公平，这时候，我们就应该拿出我们的拦截话术——“我有不同意见，不过这不是重点。”对方说了很过火的话时，我们可以先皱皱眉头，向对方传递一个信号——你惹到我了；然后坚定、清晰且不卑不亢地说：“关于这一点，我觉得你不应该这么说，不过这不是重点，我们还是来研究一下问题的解决方案吧。”\n蚂蚁搬大象式的道歉\n误区：第一条红线是试图淡化，说事情的结果并没有那么糟。第二条红线是试图撇清，说自己要负的责任并没有那么大。\n就是在道歉的时候，你要尽可能地把责任往自己身上揽，甚至包揽到一个夸张的地步。\n这招的适用范围，主要是日常生活中那些比较模糊的责任地带，而且是为了平息对方的怒火才使用的。如果是在明确追责，并且对方怎样都不会放过你的场景，比如车祸现场，当然不能主动把责任揽到自己身上。")]),n._v(" "),v("p",[n._v("用自嘲与自谦进行自我保护\n面对敌人的时候，应当用自嘲的方式提及对方已经知晓且可能会被攻击的弱点，而不必将所有弱点和盘托出，给对方更大的攻击空间。\n争取他人信任时，应该多暴露自己无关紧要的弱点。例如职场工作中，你可以大谈自己毕业学校不好，但是直接涉及工作能力的弱点最好还是尽少展现并尽可能改正。")]),n._v(" "),v("p",[n._v("第三章 说服\n一是人如何形成看法；二是人又为什么会改变看法。\n当我们要说服别人的时候，第一步就是要意识到，每个人都必须拥有对自己行为的选择权，确保它，并且善用它。\n反向提问\n关键在于，我们要改变提问的方向，来引导对方从“为什么我不能”转变为“为什么我想要”。\n因为在这段对话中，劝导者一直在做的是不断问对方“为什么你会想要”，而每问一次，听者的脑中就会思考一次“因为我要如何如何”的理由。如果这位朋友开始谈买跑步鞋的计划，或者说出决定跑步的时间，那我们当然可以很开心地表达支持。但除非他主动提问，否则此时切记别用过度的关怀让他感受到压力，因为这种行为只会重新激起对方对跑步的抗拒心理，那就前功尽弃了。\n咦，你居然会想过要这么做，我很好奇，原因是什么？\n用提问引导对方强化某个信念，同时用“我很好奇”这类中立的表述消除对方的戒心。\n有策略地请人帮忙\n要以对方为出发点，诉求要具体。更具体地强调了对方让座与不让座的区别，也更能激发出行善者脑中的画面感。\n第一步，我们必须要让对方知道，对方的行为具体能给我们带来什么改变。\n每个人在做好事的时候，最担心的就是不知道自己的善良会不会被别人利用，所以我们要努力让对方相信——他的善意是不会被糟蹋的。\n让对方有选择，相反，当我们发现在做决定时，主动权是牢牢掌握在自己手上，那么我们就会觉得安心，并自觉地放松戒备，开始认真思考各种选项的可能性。")]),n._v(" "),v("p",[n._v("朋友犯浑怎么劝\n疏导式劝阻技巧\n不要问“为什么”，要问“怎么了”\n这个时候你就会发现，问题已经从“我想做什么”变成了“我的感觉是什么样的”，而只要他能详细地说出自己的感觉，他就会慢慢觉得，做蠢事的真正动机说白了就是置口气而已。\n引导情绪宣泄，你要比你朋友更狠\n这个时候，需要的是有人跟他一起骂，最好比他还生气、比他还具体、比他还刻薄。事实上，当你骂得比你朋友更狠的时候，他才可能会冷静下来。\n与其一味阻拦，不如把计划落到实处\n绝大多数的傻事都是一时冲动干出来的，而要避免一时冲动，帮着他煞有介事地“精心策划”，其实是最好的办法。比如，打架都是头脑一热，可是你真要仔细想些实打实的问题")]),n._v(" "),v("p",[n._v("诉诸需求触及对方痛点\n所有的说服都有一个基本的道理——不要一直强调我需要什么，而是要想办法找出对方需要什么。\n如何说通年纪大、地位高的人\n用对方的视角看问题 找到长辈能听进去的理由\n比如，员工做具体工作，专注于技术问题的解决；领导负责全局统筹，专注于宏观态势的把握。看问题的层次不同，做决策的时候优先级就会不一样，即一个看重于把事做成，一个看重于别出乱子。这才是领导之所以比较保守的根本原因。一般情况下，领导能够明白员工为什么这么想，员工却很难知道领导真正关心的是什么。如果我们不试着从一个更高的层面去理解，只知道掰扯自己的道理，就算领导驳不倒我们，我们的沟通也一定是无效的。\n找到对方感同身受的痛点\n又比如，我们要推进一个项目，但是领导觉得风险太大。在劝领导的时候，我们不要太多强调收益，更多地要强调风险规避；不要太多强调创意（什么行业先行者啊、领先多少年啊，这些会让领导越听越害怕），更多地要强调市场的可行性（即别人也有干成过的）。\n给对方一套完整的解决方案")]),n._v(" "),v("p",[n._v("如何催促拖延症老板\n减少焦虑，提供动力\n第一步：真诚表示体谅，实现低阻力沟通 您最近这么忙，工作又多，应付得过来吗？\n第二步：提供后备方案，清空焦虑内存 您要是没时间处理这个事，我们用方案B怎么样？\n第三步：点明短期收益，激发主体动力不过如果您能抽时间处理这个事，我们能获得更多的好处喔。")]),n._v(" "),v("p",[n._v("如何说服比自己更专业的人\n尊重专业，达成共识\n克制直接表达主观感受的冲动，讨论一旦落到主观判断领域，我们和设计师就很容易陷入各说各话的争执。把主观上的不满意细化成客观和具体的问题。我们应该跟自己印象中那些“不土”的设计进行比较，并告诉设计师，是字体太过古板和常规，还是配色太沉闷，抑或是排版太密集。就算在脑海中搜索不到什么可以对比的案例或进行描述的词语，我们还可以上网搜索一下类似的设计，以供设计师捕捉我们的想法。\n提出抽象需求，而不是具体要求\n需求是整个设计项目应该达到的总体目标，要求则是指对设计方案中某个细节的具体安排。同样都是改成绿色，与其直接要求设计师改，不如让设计师提供可行性方案让我们来挑。\n所有和专业人士的沟通交流都建立在前期明确传达需求的基础上，掌握说服技巧的同时，我们更需要在前期沟通上多付出一些努力，将方案需求描述得更清楚，甚至通过提前熟悉对方领域或找类似风格作品等方式向对方传达需求，避免后期反复修改的麻烦。")]),n._v(" "),v("p",[n._v("创造压力改变双方立场 诉诸外部压力进行说服\n塑造共同的敌人，可以免伤和气。\n化主观意见为客观压力，让对方更容易接受我们的意见。")]),n._v(" "),v("p",[n._v("营造机不可失的时间紧迫感\n让时间紧迫感帮你完成说服 所以在通常状况下，人的大脑会偷懒，它会试着用最省事的方法——先不给你电话，而是要看看你的行为和表现，等判断清楚之后再决定下一步，这叫作“决策延迟”。此时在时间的紧迫感下，人的大脑往往会从偷懒模式切换到安全模式，即用最保险的方法提前做决策。事实上，它是教你用一些很小，但却很明确的元素，重新组装我们的论点与资讯来促进改变的可能。")]),n._v(" "),v("p",[n._v("通过把人“架起来”达到劝说目的\n劝人做本不想做的事 把人“架起来” 这种说话技巧的核心，就是主动发现并拔高对方的价值  “架起来”不是凭空的，最好有个对比。")]),n._v(" "),v("p",[n._v("第四章 谈判\n所谓谈判，就是在不可忍受的僵局下，交换评价不相同的事物.\n旁敲侧击地打探消息\n同时，谈判中有些老江湖，在打听消息方面都有一种特别的本事。在谈判之前，他们从不贸然进入主题，而是以暖身的姿态跟大家聊起天，貌似不经意地抛出些不痛不痒的问题，看起来只是随便问问，甚至还让我们觉得嘘寒问暖、特别贴心，但是回过头来一想，我们的很多关键信息早就被他们摸得一清二楚了。\n三种常见的问句\n第一类：“您是怎么知道我们的？判断出对这家餐厅而言，有哪些广告投放是有效果的，有哪些杂志采访是无意义的，又有哪些群体是在背后为自己做口碑的。\n第二类：“在这方面，你们之前做过的最大的案子是多少？ 遇到双方初次合作、价格还在摸索期的情况，通常都会先跟对方聊聊：“企业培训，你们这方面累积了不少经验吧？”“之前你们经手过最大型的培训是怎样一个投入啊？”\n第三类：“按照这样的条件，我给您推荐别人好不好？”\n在大规模的正式谈判中，由于搜集信息的效益高、渠道多，所以人们相对比较愿意做功课，事前的投入也多，此时，就不太能用得到这些“旁敲侧击”的小技巧。\n所以在使用以上技巧时，你要知道它就像一把轻便的小刀，专门应对那种信息不足的临时性谈判。别因为学会了这几招就想偷懒，拿它代替你该有的正式刀具。")]),n._v(" "),v("p",[n._v("用“纠正式引导”来获取信息\n很多信息之所以需要通过某种手段来获取，很可能就是因为平常人们不愿意直接说，那么，你就算问得再清楚明白，也是得不到答案的。“\n纠正式引导”的信息获取方法\n所谓对话引导，就是作为说话人，用某些暗示或策略来引导我们的听众怎么去想、怎么行动，从而达到我们获取信息的目的。\n运用对方的纠正心理获取信息 也就是我们与其去问对方，还不如给对方一个貌似肯定的答案，引导对方来纠正我们。注意我们的态度和语调\n将信息获取的效益进一步扩大 在纠正式引导中还有一个秘诀，那就是适度的反抗，它的有效运用有可能让你获取更进一步的信息。")]),n._v(" "),v("p",[n._v("如何向老板提加薪\n用确认标准获取主动\n第一步：确认加薪标准 第二步：大大方方地和老板讨论自己的工作表现\n第三步：带着老板“想象未来” 压力诉诸第三方\n注意：因为无论是要求加薪还是其他谈判，除了终极目标之外，我们还有阶段性目标。当客观条件不允许马上实现终极目标时，能够把握住一两个阶段性目标也是不错的收获。")]),n._v(" "),v("p",[n._v("突破惯性思维进行出价\n先发制人的定锚效应\n率先出价抢得先机 报价的过程是一个心理博弈的过程，果断率先出价反而能在谈判中占尽优势。\n优势1：先报价，会给对方以“赚到”的心理感受（我是卖方）\n优势2：报价配以合适的方式，能够激活谈判桌上的“定锚效应” 所谓“定锚效应”，就是人们在衡量和判断时，总是倾向于给予最初获得的信息更多的重视，这些最初的信息就像船锚定住船的位置一样，会全程制约评估的进行。\n优势3：在果断先报价的一方开口后，另一方想要砍价，就必须讲出理由、给出承诺\n注意：先报价确实有助于将正常谈判锁定在你想要的价格区间内进行，但如果报价与对方心理预期差距较大，同样也容易吓跑客户。所以在报价前要充分评估对方的心理预期，也可以参照具有可比性的其他行业报价，在合理范围内做出对自己最有利的报价方案。")]),n._v(" "),v("p",[n._v("年轻人要敢于给自己开高价\n低价缺点：\n第一，会降低自己的产品或服务在客户心目中的价值。\n第二，就算因为价格较低，销售的速度会快一些，但定低价给自己带来的心理暗示却是消极的；产品的档次和出售的平台完全不同，也容易给自己带来低人一等的感觉，成为阻碍年轻人奋斗的心魔。\n第三，低价或许会让自己所定的价格很可能配不上自己提供的服务或产品，最后亏的还是自己。\n很多年轻人会担心：开高价，是不是反而会很容易被别人砍价啊？可是我们要明白，既然是做生意，就一定会碰到讨价还价的人，甚至是讲价高手。而且，很多爱砍价的人，不管我们开多低的价，他还是会觉得不够低，问题不是我们的价格开得高，而是对方这种占便宜的心态。我们开价再低，碰上这种人，他都是要砍的。\n在这里需要特别提醒大家的是，这则技巧有它的适用范围：自己创业 而且没有客观的指标来定价，比如文创艺术作品、设计类、高端服务类等，这样客户没有办法做横向对比，会给我们留下弹性定价的空间。\n最后，身为经验不足的年轻人，开出的高价确实可能会有不妥之处。因此，当遇到客户有理有据的质疑，不妨认真询问他们的真实想法：一则可以通过进一步的沟通获取更多信息，有利于之后的判断；二则也可以从中学习，方便之后进行策略上的调整。")]),n._v(" "),v("p",[n._v("在让步中谈成交易\n几乎没有人能单靠出价而谈成一笔交易，所有人都是靠着成功的让步策略来让对方点头的。\n砍价中要学会“掀桌”\n掀桌砍价三步法\n第一步：表达上桌意愿，把对方也拉到谈判桌上来\n一步步地增加对方的沉没成本。\n第二步：等对方上桌，再讲出还有不太友好的其他人也在桌上\n第三步：条件成熟，果断掀桌 而即便不成功，我们也是有退路的，我们完全可以做痛心疾首状，说：“今儿我就不管我老婆了，老板，就按你的价买了！”\n所以，掀桌的核心不在于掀桌这个行为，而在于“先把对方请上桌”和“营造一张安全网”。")]),n._v(" "),v("p",[n._v("跳崖式让步法则\n误区：挤牙膏 其实，当我们发现自己的谈判对手是那种挤一下、让一点的个性时，就算我们真的快要踩到了对方的底线，肯定也不会相信，我们肯定会再给他点压力试试看。\n所谓“跳崖”就是：一开始我们一步都不退，等对方的压力累积到了一定的程度后，再一口气做出一个戏剧性的大让步。\n这就是跳崖式让步，它包含了三个元素：\n第一，咬定自己原本的底线，累积压力，不轻易退让。\n第二，出于某种特殊的原因我们突然松动，愿意一口气做出大幅的让步，但也因如此，这个特殊的让步是仅此一次的。\n第三，要表示出决绝的态度，要让对方明白，如果在已经做出大幅的让步后还要再还价，就未免欺人太甚了。\n跳崖式让步最关键的就是在一次降价之后绝不能再降，不然之前的努力就会全部白费，又进入挤牙膏式的循环。")]),n._v(" "),v("p",[n._v("陷入僵局时不如搁置\n当我们彼此的冲突一时无法化解的时候，与其冒着触礁的风险急着推动进度，还不如试着转化或搁置主要矛盾，从其他虽不相关但还谈得下去的议题入手。\n化解谈不下去的危机\n很多人在谈判进入僵局时，只会重复同样的话试图让对方改变。这是不切实际的想法。当谈判进入僵局时，重复同样的话只会让场面越来越僵。\n寻找原因\n其实谈判陷入僵局的原因不外乎三种。有两句话可以让大家绕开这三块挡住谈判的绊脚石，从而突破僵局。\n第一句话：“咱们都是爽快人，这事儿今天就定下来，好不好？”\n第一块绊脚石——没意愿 另一块绊脚石——没授权\n第二句话：“想想有什么新方案，咱俩都能接受。”\n第三块绊脚石——求独赢\n谈判从来没有万全的方法保证一定成功，我们要做的是提高成功的概率。另外，如果对方确实缺乏诚意，那我们就真没必要空耗下去，谈判的小船该翻就翻，果断地结束，让它直接破局，也是一种打破僵局的方法。")]),n._v(" "),v("p",[n._v("把是非题变成选择题\n其实不是我说能不能便宜点，是要看您要的是质量还是价格啊。\n当然这个我也可以做，但是时间这么紧，执行的品质可能不太高。")]),n._v(" "),v("p",[n._v("要辞职，怎么说\n要素1：告知去处 要素2：慎选理由 要素3：表示感激")]),n._v(" "),v("p",[n._v("第五章 演讲\n如何做胜选演讲\n忽略胜利，关照众人 赞美对手 弥合分歧 第三步：感谢盟友\n我们在做胜选演讲的时候，首先要明白一件事：当你的胜利已经成为既定事实，它就已经不重要了。因为你就算不说，所有人也都知道你是最终的胜利者。这个时候，就应该致力于怎样将除了你之外的其他人照顾好——他们可不是胜利者，但多关照一下他们，却能让你的这次胜利变得更有价值。")]),n._v(" "),v("p",[n._v("如何做败选演讲\n优雅地表现不服\n第一点：我不是彻底的输家\n第二点：我输了，但我没错\n第三点：你赢是侥幸，我输是有客观原因\n第一，\t感谢盟友。第二，威胁对手。第三，澄清误解。第四，重建形象。\n选演讲的目的很大程度上是为了继续保持存在，在失败后还把自己的支持者团结在自己身边，以备将来东山再起。")]),n._v(" "),v("p",[n._v("如何在大家不想听的时候发言\n点破尴尬，讲给重要的人听 明确主题 点破了尴尬，自嘲之后，该讲的话还要认认真真地讲，这样才对得起我们的身份和任务。找对听众（话说给谁听的）")]),n._v(" "),v("p",[n._v("避免说话啰唆\n帮你捋清思路\n方法1：先问再答\n现在跟活人说话，就可以通过反问帮助聚焦，把主观题变成选择题，限缩答案，避免啰唆。\n方法2：看人下菜碟\n所以我们说话的时候，非常需要大家进入听众的角色，去预判他们的年龄、职业、关系，以及对所谈话题的理解程度、熟知程度，从而帮助我们做减法。根据不同的听者，决定省略什么、保留什么，这就是“看人下菜碟”。\n方法3：先讲中心句  我认为是这样的，原因有三点……\n先讲中心句，再说原因或其他描述类语言。")]),n._v(" "),v("p",[n._v("辩论 通过对抗争取第三方支持\n反应慢怎么办\n第一招：复述问题 第二招：慢而不断 我们的逻辑线不能断 第三步 化繁为简 反应慢，是因为问题太多应接不暇，那不用想那么多问题不就可以了吗？其实很多时候，无数个小问题都可以包含在一个大问题里面。只要掌握了这个大问题，就可以把那些小的东西归纳进来，不用一个一个去回应，自然就不存在反应不过来的问题了。")]),n._v(" "),v("p",[n._v("怎样回应陷阱式提问\n点破意图\n第一步：增强意识，发现陷阱\n第二步：斥责刨坑者的动机\n需要说明的是，我们这里讲的陷阱大多是面对公众，你的回答可能会在舆论中被误解，所以才需要格外注意。")]),n._v(" "),v("p",[n._v("反忽悠的心智免疫法\n第一步：关键词脱敏，做到态度免疫\n第二步：模拟辩论，做到论点免疫\n第三步：模仿表达，做到影响力免疫")]),n._v(" "),v("p",[n._v("辩论的核心能力是反驳\n如何反驳“认真你就输了”\n抛开输赢\n第一步：“我在讲道理，只有你在讲输赢”\n第二步：“如果讲输赢，那你已经输了”\n辩论中有一个常用技巧，叫作“同理反抽”，意思是根据对方的逻辑（同理），得出反驳对方的结论（反抽）\n第三步：“嫌我认真，我就要更认真”\n所以，在对方被我们噎得说不出话的时候，我们要重新定义他对于输赢和辩论的认知：“傻孩子，所有的辩论，目的都是为了解决问题，所以辩论本身就是一件很认真的事。如果我们不认真，干吗在这里浪费时间呢？我不知道认真会不会赢，但是我知道不认真就一定会输。现在，我们就一起来认真地讨论一下问题吧。”")]),n._v(" "),v("p",[n._v("在这里，我们首先是在目的上显得比对方更为成熟大气，完全不是为了发泄情绪；其次，在输赢看法上，化你死我活的输赢争夺为大家一起解决问题的双赢解决方案。")]),n._v(" "),v("p",[n._v("如何反驳“你行你上”\n责任反弹\n他们就是想把自己应该承担的责任丢给我们，所以这时候我们的第一反应应该是稳稳接住对方的呛声并且反弹回去。\n方法1：澄清各自的角色 鸡蛋\n方法2：指出对方在逃避\n“你行你上”这句话的核心逻辑是：如果你有这个能力把事做好，就应该直接把这件事做了；如果你有更好的方案，就应该直接提出，总之你不许说我。所以在实际使用中，“你行你上”这种说法，往往只是对方为了逃避责任的托词。这个时候，你完全可以大大方方地承认自己就是不行，把对方架在制高点上，使其下不来台。\n方法3：锁定对方的责任\n不知大家有没有想过，我们看某个人不顺眼，仅仅是因为他事情办得不够好吗？不。我们之所以不爽到一定要批评某个人，是因为他占据了位置、消耗了资源，还排挤了其他可能把事情办好的人，这就叫“机会成本”。因为这个世界本来就不是或至少不完全是“谁行谁上”的，上位的机会那么有限，有你在，其他人就没有机会。\n所以在大多数情况下，“我做到这一步已经很不错了”并不足以为你辩护，因为很有可能别人会比你做得更好。所以，对方最大的责任不是事情没做好，而是浪费了世上最稀缺的资源——机会。")]),n._v(" "),v("p",[n._v("破解对方的精彩类比\n角度1：可以试试指出类比之中的不当之处\n道理很简单：拿A来类比B，一定意味着A与B既有相似性，又不完全等同。相似，就有可比性；不等同，就一定也有不可比性。对方强调可比性，这是对方的自由；我们进一步地指出其中的不可比性，这是我们的自由。不管对方的类比是什么，你指出其中不当的地方就可以了。\n角度2：可以顺承对方的类比进行延伸阐述。")]),n._v(" "),v("p",[n._v("拒绝上级的不合理安排\n第一步：战略上高度肯定\n第二步：成本上精密核算\n我们站在老板的角度想一想：下属说“不”，唯一的正当理由就是这件事本身划不来，而下属难免有偷懒的嫌疑，所以必须有翔实的论据表明这件事真的就是成本太高，才能打消老板的怀疑。\n第三步：决策权完全上交")]),n._v(" "),v("p",[n._v("避免被别人“架起来”\n当遇到别人给你戴高帽的时候，比较聪明的方法不是拒绝那顶高帽，而是把高帽戴上去，借着高帽的威严，提出不一样的要求。\n当别人有求于我们的时候，由于我们是刻意要戴着别人递来的高帽子讲话，所以在摆出姿态的同时，要注意对方请求的性质。在不同的情况下，你的态度要有微妙的不同。比如朋友之间的敬酒，你要用半开玩笑、半认真的态度来说；而当对方是认真地托付你办事情，那拒绝的时候就要同样认真严肃地表达。")])])}),[],!1,null,null,null);v.default=l.exports}}]);